# Return value (bottom-up): when answer builds from subtree results
# Example: max depth
def maxDepth(node):
    if not node:
        return 0
    return 1 + max(maxDepth(node.left), maxDepth(node.right))

# Nonlocal (side-effect): when answer combines info from different subtrees
# Example: diameter (longest path may not pass through root)
def diameter(root):
    best = 0
    def dfs(node):
        nonlocal best
        if not node:
            return 0
        l = dfs(node.left)
        r = dfs(node.right)
        best = max(best, l + r)  # path through this node
        return 1 + max(l, r)     # height for parent
    dfs(root)
    return best

